using System;
using System.Net.Http;
using Microsoft.AspNetCore.Mvc;

namespace WebhookProxy
{
    public class ProxyController : ControllerBase
    {
        private readonly HttpClient _httpClient;

        public ProxyController(IOptions<WebhookOptions> options)
        {
            _httpClient = new HttpClient();
            _httpClient.BaseAddress = new Uri(options.Value.Url);
        }

        [HttpPost]
        public async Task<IActionResult> HandleRequestAsync([FromBody] string requestBody)
        {
            var response = await _httpClient.PostAsync("", new StringContent(requestBody, Encoding.UTF8, "application/json"));
            return Ok(await response.Content.ReadAsStringAsync());
        }
    }
